from flask import Flask, request, send_file, redirect, url_for
from flask_sqlalchemy import SQLAlchemy
from flask_login import LoginManager, UserMixin, login_user, current_user, logout_user
from PIL import Image
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['SECRET_KEY'] = 'your_secret_key'
db = SQLAlchemy(app)
login_manager = LoginManager()
login_manager.init_app(app)
UPLOAD_FOLDER = 'static/profile_pictures'
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg'}

class User(db.Model, UserMixin):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    profile_picture = db.Column(db. String(), default='default.png')

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

if not os.path.exists(app.config['UPLOAD_FOLDER']):
    os.makedirs(app.config['UPLOAD_FOLDER'])

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/upload-profile-picture', methods=['POST'])
def upload_picture():
    if request.method == 'POST' and 'file' in request.files:
        file = request.files['file']
        if file.filename != '':
            if file and allowed_file(file.filename):
                filename = secure_filename(file.filename)
                file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
                user_id = current_user.id
                db.session.query(User).filter_by(id=user_id).update({User.profile_picture: filename})
                db.session.commit()
        return redirect(url_for('view_profile'))
    else:
        return "Invalid request", 400

@app.route('/view-profile')
def view_profile():
    if current_user.is_authenticated:
        username = current_user.username
        profile_picture = User.query.filter_by(username=username).first().profile_picture
        return send_file(os.path.join(app.config['UPLOAD_FOLDER'], profile_picture), as_attachment=True)
    else:
        return redirect(url_for('login'))

